// Adapta el payload del sink n8n del lead bot (src/lib/leadBot/sinks/n8n.ts)
// al formato que espera el CRM Inmobiliario en /api/homes/ingest/web-form.
const body = $json.body || $json;
const user = body.user_data || {};
const q = body.qualification || {};
const conv = body.conversation_data || {};
const conversion = body.conversion || {};
const tracking = body.tracking || {};

const classification = String(q.classification || 'NURTURE').toUpperCase();
const priorityByClassification = { SQL: 'alta', MQL: 'media', NURTURE: 'baja' };
const statusByClassification = { SQL: 'interesado', MQL: 'nuevo', NURTURE: 'nuevo' };

const summaryParts = [
  conv.advisor_summary ? `Resumen para asesor:\n${conv.advisor_summary}` : null,
  `Clasificacion: ${classification} (${q.score ?? 0}/100)`,
  q.intent && q.intent !== 'indefinido' ? `Intencion: ${q.intent}` : null,
  q.project ? `Proyecto: ${q.project}` : null,
  q.budgetStatus ? `Capacidad: ${q.budgetStatus}` : null,
  q.timeline ? `Plazo: ${q.timeline}` : null,
  q.decisionRole ? `Decision: ${q.decisionRole}` : null,
  conversion.recommended_action ? `Accion recomendada: ${conversion.recommended_action}` : null,
].filter(Boolean);

const lead = {
  providerEventId: `lead-bot:${user.client_id || ''}`,
  name: user.name,
  email: user.email,
  phone: user.phone,
  interesting: q.project || q.intent || 'homes',
  message: `${conv.latest_user_message || 'Lead generado desde bot Homes'}\n\n${summaryParts.join('\n')}`,
  timestamp: tracking.timestamp || new Date().toISOString(),
  source: 'chatbot_homes',
  sourceDetail: tracking.pathname || 'chatbot_homes',
  transactionType: q.intent === 'alquilar' ? 'alquilar' : 'comprar',
  profileType: q.intent === 'invertir' ? 'inversor' : 'consumidor',
  prioridad: priorityByClassification[classification] || 'baja',
  estado: statusByClassification[classification] || 'nuevo',
  bot_status: ['schedule_call', 'whatsapp_handoff'].includes(conversion.recommended_action) ? 'asesor' : 'bot',
  utmSource: tracking.utmSource,
  utmMedium: tracking.utmMedium,
  utmCampaign: tracking.utmCampaign,
  rawPayload: body,
};

if (!lead.email && !lead.phone) {
  throw new Error('El lead debe tener email o telefono');
}

return [{ json: lead }];
